function CryptoPortfolio() {
  const [holdings, setHoldings] = React.useState([
    { coin: 'BTC', amount: 0.45, price: 67200 },
    { coin: 'ETH', amount: 4.2, price: 3450 },
    { coin: 'SOL', amount: 35, price: 148 },
    { coin: 'ADA', amount: 5000, price: 0.52 }
  ]);

  const total = holdings.reduce((sum, h) => sum + h.amount * h.price, 0);

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column' }}>
      <h2 style={{ margin: '0 0 12px', fontSize: 18 }}>Crypto Portfolio</h2>
      <div style={{ fontSize: 24, fontWeight: 700, color: '#22c55e', marginBottom: 12 }}>${total.toLocaleString(undefined, {maximumFractionDigits: 2})}</div>
      <div style={{ flex: 1, overflow: 'auto' }}>
        {holdings.map((h, i) => (
          <div key={i} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 0', borderBottom: '1px solid #334155' }}>
            <div>
              <div style={{ fontWeight: 600 }}>{h.coin}</div>
              <div style={{ fontSize: 12, color: '#94a3b8' }}>{h.amount} @ ${h.price.toLocaleString()}</div>
            </div>
            <div style={{ textAlign: 'right' }}>
              <div style={{ fontWeight: 600 }}>${(h.amount * h.price).toLocaleString(undefined, {maximumFractionDigits: 2})}</div>
              <div style={{ fontSize: 12, color: '#22c55e' }}>+{(Math.random() * 5).toFixed(2)}%</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<CryptoPortfolio/>);
